sql:
SELECT stage_name
FROM growth_stages
WHERE stage_id = 1;

SELECT input_type, input_quantity
FROM treatment_inputs
WHERE treatment_id = 0;

SELECT plot_number, COUNT(trial_id) AS total_trials_per_plot
FROM field_trials
GROUP BY plot_number;

SELECT plot_id, location
FROM plots
WHERE location = 'Field B';

SELECT COUNT(trial_id) 
FROM field_trials 
WHERE season = 'spring' AND stage = 'R4';

SELECT treatment_id, MAX(input_quantity)
FROM treatment_inputs
GROUP BY treatment_id;

SELECT COUNT(DISTINCT plot_number) AS total_plots, COUNT(trial_id) AS total_trials
FROM field_trials
WHERE stage = 'R4' AND k_rate_lbac > 10.0;

SELECT trial_id, stage
FROM field_trials
WHERE plot_number = 1;

SELECT access_id, access_device
FROM trial_access_logs
WHERE access_type = 'edit';

SELECT trial_id, stage, k_rate_lbac
FROM field_trials
WHERE k_rate_lbac = (SELECT MIN(k_rate_lbac) FROM field_trials);

SELECT stage_name, stage_order
FROM growth_stages
WHERE stage_order > 5;

external_knowledge:
- 'Treatments applied' refers to the specific interventions like fertilizer types used during the trials;
- 'Growth stages' are specific phases of crop development such as R4 (kernel dough stage) for corn;
- The term 'K rate in lb/ac' refers to the potassium application rate measured in pounds per acre;
- 'Seasons' could refer to the agricultural growing seasons like spring, summer, fall, etc., during which the trials were conducted;
- 'Soil types' denote the classification of soil based on texture, composition, and other properties.
